"""
MKT Original Language Commentary — Job chapters 12–14
Run: python3 scripts/zc-original-job-12-14.py
Verses: ch12×25 + ch13×28 + ch14×22 = 75

Key notes:
- ch12: YHWH appears only here (v9) in the poetic core of Job — the poem otherwise
  uses ʾĒl, Ĕlôah, Šaddai; v9's YHWH is likely a frozen idiom or proverbial citation.
- ch13: legal vocabulary dominates — mišpāṭ, rîḇ, tôḵaḥat, ʿāraḵ; Job petitioning
  the divine court directly. v15 is the most-disputed verse in the book: qere/ketib
  variant pits 'lō' (no hope) against 'lô' (in him), most versions follow the
  traditional reading "yet will I trust."
- ch14: the meditation on human mortality; v14's resurrection question ('if a man
  dies, will he live again?') is the book's deepest probe; v15 pivots to a vision of
  restored fellowship; v1 'born of woman' recurs at 15:14; 25:4 and enters the NT.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JOB1214 = {
  "12": {
    "1": "<p><span class='term'>wayyaʿan ʾîyôḇ</span> — the standard narrative formula (vayya'an + name) that opens each of Job's replies; the book's speeches alternate between three cycles of the friends and Job. Job's reply here comes after Zophar's first speech (ch. 11), where Zophar claimed to know the depths of God and accused Job of hidden sin.</p>",
    "2": "<p><span class='term'>ʾattēm ʿām</span> — 'you are <em>the</em> people' — a cutting irony: ʿām normally means 'a people' or 'the people' as a collective, but used singularly of these three men it implies they fancy themselves the entire repository of wisdom. <span class='term'>wĕʿimmaḵem tāmûṯ ḥāḵmāh</span> — 'and wisdom will die with you' — sarcasm; if wisdom dies when they die, it is as fragile and contingent as they are. The verse targets the friends' assumed epistemic privilege.</p>",
    "3": "<p><span class='term'>lēḇāḇ</span> — 'mind/heart' in the full biblical sense of the seat of understanding and will, not just emotion. <span class='term'>nōpēl ʾānōḵî mimmkkem</span> — 'I do not fall below you' — the verb nāpal (to fall) used figuratively for status inferiority; Job denies any intellectual subordination. The rhetorical question 'who does not know such things?' dismantles the friends' claim to special insight: the doctrine they proclaim is the most common possible orthodoxy, not hidden wisdom.</p>",
    "4": "<p><span class='term'>śĕḥôq lĕrēʿēhû</span> — 'a laughingstock to his neighbor' — śĕḥôq is laughter in the mocking sense (cf. Gen 21:9, where Ishmael 'mocks'). The following phrase is the scandal: the one who becomes a laughingstock is <span class='term'>qārāʾ ʾel-ʾĕlôhîm wayyaʿănēhû</span> — 'who called to God and he answered him.' Answered prayer is supposed to mark the righteous; Job's answered-prayer history makes his current mockery a theological scandal. <span class='term'>ṣaddîq tāmîm</span> — 'just and blameless' — the precise epithets from 1:1 and 1:8 (God's own verdict); Job now deploys them of himself, underscoring the contradiction.</p>",
    "5": "<p><span class='term'>lappîḏ</span> — torch/lamp; in the thought of the prosperous man, the lamp of the afflicted (one who is stumbling, <span class='term'>nākôn lĕmiʿad rāgel</span> = 'ready to slip with the foot') is an object of contempt rather than compassion. The verse indicts the comfort-bias of prosperity theology: the comfortable naturally interpret the stumbling of others as moral failure rather than undeserved calamity.</p>",
    "6": "<p><span class='term'>šālēwû</span> — 'undisturbed/at ease' (from šālāh) — the friends' retributive framework is undermined by the observable fact that the tents of violent men are <em>šālēwû</em> while the righteous Job suffers. <span class='term'>ʾăšer hēḇîʾ ʾĕlôhîm bĕyādô</span> — 'into whose hand God has brought [it]' — an ironic acknowledgment that God himself facilitates the security of those who provoke him, which is precisely what the friends' theology cannot accommodate.</p>",
    "7": "<p>Job shifts to a wisdom-hymn structure using the 'ask the creation' motif — <span class='term'>šĕʾal-nāʾ bĕhēmôṯ</span> (ask the animals), <span class='term'>ʿôp̄ haššāmayim</span> (birds of the air). The appeal to non-human creation as teacher is a striking rhetorical move: the very creatures who cannot speak or reason are more reliable instructors than the friends. The four creation-witnesses (animals, birds, earth, fish) form an ascending cosmic series.</p>",
    "8": "<p><span class='term'>śîaḥ lāʾāreṣ</span> — 'speak to the earth' — śîaḥ normally means to reflect or meditate (the word for meditation in Ps 1:2 is also from this root); here it is the activity of conversing with the earth itself. <span class='term'>ḏāgê hayyām yĕsappĕr-lāḵ</span> — 'the fish of the sea will declare it to you' — the fish use sāpar (the verb for counting and narrating); the same verb governs Ps 19:1-2 (the heavens <em>sāpar</em> the glory of God). Creation does theology that the friends have missed.</p>",
    "9": "<p><span class='term'>mî lō-yāḏaʿ bĕḵol-ʾēlleh</span> — 'who does not know in all these?' — rhetorical question capping the creation-witness section. The grammatically significant feature is what follows: <span class='term'>kî yaḏ-YHWH ʿāśṯāh zōʾṯ</span> — 'that the hand of <em>YHWH</em> has done this.' This is the only occurrence of the divine name YHWH in the poetic core of Job (chs. 3–42:6); throughout the poetry the terms are ʾĒl, Ĕlôah, Šaddai. Most scholars regard v9 as preserving a traditional idiom or cited proverb, since the narrator and the divine speeches freely use YHWH but the poetry avoids it.</p>",
    "10": "<p><span class='term'>ʾăšer bĕyāḏô nep̄eš kol-ḥay</span> — 'in whose hand is the life (nepeš) of every living creature' — nepeš here is not 'soul' in the platonic sense but the animating life-force; the full phrase 'the breath of all human flesh' (<span class='term'>rûaḥ kol-bĕśar-ʾîš</span>) pairs the immaterial animating breath with its bodily vehicle. Divine sovereignty over all life is the theological premise underlying the creation-teacher argument of vv7-9.</p>",
    "11": "<p><span class='term'>hăʾōzen millîn tiḇḥān</span> — 'does not the ear test words?' — the sense-metaphor of tasting: the root of <span class='term'>tiḇḥān</span> is bḥn (to test/assay); the parallel <span class='term'>ḥēk</span> is the palate/roof of the mouth that discerns taste. The verse rebukes the friends by analogy: as the palate can taste good food from bad, a discerning mind should be able to hear the difference between genuine wisdom and false comfort. The ear-as-taster metaphor recurs in 34:3.</p>",
    "12": "<p><span class='term'>bĕyĕšîšîm ḥāḵmāh</span> — 'with the aged is wisdom' — a conventional wisdom maxim the friends would affirm. <span class='term'>ûbōrek yāmîm tĕḇûnāh</span> — 'and with length of days, understanding.' Job states the truism ironically, as a setup for v13: these conventional attributes are not the possession of aged humans but of God himself. The verse performs a rhetorical reversal: yes, wisdom belongs to the ancient — the most ancient of all.</p>",
    "13": "<p><span class='term'>ʿimmô ḥāḵmāh ûgĕḇûrāh</span> — 'with him are wisdom and strength' — the verse transfers the attributes of v12 (aged human wisdom) to God exclusively; the poetic shift is marked by the pronoun ʿimmô ('with him' = God) displacing the human subject. <span class='term'>ʿēṣāh ûṯĕḇûnāh</span> — 'counsel and understanding' — this exact tetrad (ḥāḵmāh, gĕḇûrāh, ʿēṣāh, tĕḇûnāh) reappears in Isa 11:2 as attributes of the messianic king on whom the Spirit rests; Job recites God's essential nature.</p>",
    "14": "<p><span class='term'>yihrōs</span> — 'he tears down' (from hāras, to demolish); <span class='term'>wĕlō yibbāneh</span> — 'and it cannot be built again' — the absolute finality of divine demolition contrasted with human rebuilding. <span class='term'>yisgōr ʿal-ʾîš</span> — 'he shuts up against a man' — the preposition ʿal gives the sense of imprisoning; the parallel is God locking a man in and there being no release (<span class='term'>wĕlō yippāṯēaḥ</span>). The verse begins a hymn of divine sovereignty that continues through v25.</p>",
    "15": "<p><span class='term'>yiṣrōr</span> — 'he holds back' (from ṣārar, to bind/restrict); applied to waters, the holding-back/releasing pattern demonstrates God's absolute control of natural forces. <span class='term'>wĕyišlaḥēm wĕyahpĕḵû ʾāreṣ</span> — 'he releases them and they overturn the earth' — the two antithetical divine acts (withhold/release) frame the absolute range of divine authority over hydrology.</p>",
    "16": "<p><span class='term'>ʿōz ûṯûšîyyāh lô</span> — 'strength and effective wisdom are his' — <span class='term'>tûšîyyāh</span> is a rare and distinctively Joban term (also in 6:13; 11:6; 26:3; and Proverbs 2:7; 3:21; 8:14), often rendered 'sound wisdom' or 'effective power'; it has the sense of resourcefulness that achieves results. The phrase <span class='term'>haššōgēg ûhamašgeh</span> — 'the one who errs and the one who causes to err' (i.e., the deceived and the deceiver) — is striking: both belong to God, which means divine sovereignty comprehends even error and deception, not merely righteousness.</p>",
    "17": "<p><span class='term'>môlîḵ yôʿăṣîm šōlāl</span> — 'he leads counselors away stripped' — šōlāl means naked/stripped of possessions, used of prisoners of war being led away stripped; applied to 'counselors' (yôʿăṣîm, plural of yāʿaṣ), it is deeply ironic. <span class='term'>wĕšōp̄ĕṭîm yĕhôlēl</span> — 'and turns judges into fools' — hōlēl (from hll used in the pi'el for 'to make foolish') applied to those who administer justice. The reversal-of-dignity hymn begins here and runs through v25.</p>",
    "18": "<p><span class='term'>mûsar mĕlāḵîm pittēaḥ</span> — 'he loosens the belt/authority of kings' — <span class='term'>mûsar</span> here is not 'discipline' (its common sense) but the bound garment or sash/authority-girdle worn by kings; loosening it symbolizes stripping of royal authority. <span class='term'>wayyeʾsōr ʾēzôr bĕmoṯnêhem</span> — 'and girds a servant's cloth around their loins' — the reversal is complete: the royal girdle removed, a servant's cloth applied. The royal humiliation imagery will be echoed in Isa 20 and the suffering-servant passages.</p>",
    "19": "<p><span class='term'>hakkōhănîm</span> — priests — Job includes priests in the list of those God strips, alongside counselors, judges, kings (v18), elders (v20), and princes (v21). The comprehensiveness of the list (military, legal, cultic, political leadership) suggests that no human institution is insulated from divine reversal. <span class='term'>wĕʾêṯānîm yĕsallēp̄</span> — 'and overturns those who were established/mighty' — ʾêṯānîm is 'enduring streams' / 'perennial' (cf. Amos 5:24), applied to those who seemed permanently established.</p>",
    "20": "<p><span class='term'>sēp̄er sāp̄ at neʾĕmānîm</span> — 'he removes the speech of the trusted' — sāpar in the sense of removing/taking away (cf. Gen 8:13, the surface of the earth 'was dry'); neʾĕmānîm are those who are trustworthy/reliable. <span class='term'>ûṭaʿam zĕqēnîm yiqqāḥ</span> — 'and takes away the discernment of the aged' — ṭaʿam is taste/discernment (the same root as v11's palate metaphor), applied here to the deliberative wisdom of elders. The verse directly undermines the friends' appeal to age and reliability as credentials.</p>",
    "21": "<p><span class='term'>šôpēḵ bûz ʿal-nĕḏîḇîm</span> — 'he pours contempt on nobles' — the verb šāpak ('to pour out') is used of pouring water or blood; 'contempt/dishonor' poured like water onto those of high status. <span class='term'>wĕḥezqaṯ ʾappîqîm rippāh</span> — 'and loosens the strength of the mighty' — ʾappîqîm are 'channels' or 'strong places' (the root means to be strong, to restrain); loosening their strength is the undoing of every earthly power structure.</p>",
    "22": "<p><span class='term'>mĕgalleh ʿămûqôṯ miṇ-ḥōšeḵ</span> — 'he brings to light deep things from darkness' — ʿămûqôṯ (deep things, from ʿāmōq) also appears in Dan 2:22 (God 'reveals deep and hidden things') and 1 Cor 2:10 (the Spirit searches 'the depths of God'). <span class='term'>ṣalmāwet</span> — 'shadow of death' — one of Job's signature terms (occurring 10 times in Job out of 18 total OT uses); a compound of ṣēl (shadow) + māwet (death), a word for extreme darkness that Ps 23:4 deploys for the valley of mortal danger. God brings even what is hidden in death-shadow into the open.</p>",
    "23": "<p><span class='term'>maśgîʾ laggôyim wayyaʾbĕḏēm</span> — 'he makes nations great, then destroys them' — the juxtaposition of national enlargement and destruction within a single verse shows the rapidity and totality of divine sovereignty over history. <span class='term'>šōṭēaḥ laggôyim wayyanḥēm</span> — 'he expands them and then leads them away' — nāḥāh can mean to guide/lead (like a shepherd), ironic here since the leading results in exile or dispersal. The verse anticipates the Deuteronomic theology of nations rising and falling by divine decree.</p>",
    "24": "<p><span class='term'>mēsîr lēḇ rāʾšê ʿam-hāʾāreṣ</span> — 'he strips the heart from the leaders of the peoples of the earth' — lēḇ (heart = understanding/mind) removed from the ruling class; without lēḇ they cannot govern. <span class='term'>wayyatʿēm bĕtōhû lō-ḏāreḵ</span> — 'and makes them wander in tōhû without a path' — <span class='term'>tōhû</span> is the primordial formlessness of Gen 1:2 ('without form and void'); the cosmos-undoing word applied to the condition of leaderless nations stumbling through pathless wilderness. The cosmic resonance is deliberate.</p>",
    "25": "<p><span class='term'>yĕmašaššû-ḥōšeḵ wĕlō-ʾôr</span> — 'they grope in darkness without light' — <span class='term'>māšaš</span> is tactile groping, the same verb used of the blind Philistines in Judg 16:26 and of the Egyptians in the darkness plague (Exod 10:21). <span class='term'>wayyatʿēm kĕšikkôr</span> — 'and he makes them stagger like a drunkard' — the drunkenness motif for divine disorientation recurs in Isa 29:9; 63:6; Jer 25:27. The chapter ends with the powerful image of once-glorious national leaders reduced to blind, lurching figures in the dark.</p>"
  },
  "13": {
    "1": "<p><span class='term'>hēn-kōl rāʾăṯāh ʿênî</span> — 'lo, all of this my eye has seen' — the direct sensory claim; Job opens his reply asserting first-person ocular witness. <span class='term'>šāmĕʿāh ʾāznî wattāḇen lāh</span> — 'my ear has heard and understood it' — the use of both eye and ear establishes comprehensive apprehension; Job has perceived both the observable facts and their meaning. He is not speaking from ignorance but from full-sensory witness that matches or exceeds the friends'.</p>",
    "2": "<p><span class='term'>kĕdaʿtḵem yāḏaʿtî gam-ʾānî</span> — 'what you know, I know too' — the emphatic gam-ʾānî ('even I') and the repetition of the root yāḏaʿ insist on equal epistemic standing. <span class='term'>lō-nāp̄ēl ʾānōḵî mimmkem</span> — 'I do not fall below you' — the same negated-nāpal construction as 12:3; the repetition of the claim across these two chapters suggests it is a rhetorical refrain challenging the friends' implicit intellectual superiority claim.</p>",
    "3": "<p><span class='term'>ʾûlām ʾănî ʾel-Šaddai ʾădabbēr</span> — 'surely I want to speak to El Shaddai' — <span class='term'>ûlām</span> is an adversative particle marking a sharp contrast with what precedes: 'yes, I know what you know — but what I actually want is to argue before God directly.' <span class='term'>wĕhôḵēaḥ ʾel-ʾĒl ʾeḥpōṣ</span> — 'and to argue my case before El' — hôḵēaḥ is from yāḵaḥ (to rebuke, argue, adjudicate); Job is invoking the legal connotation explicitly. He wants not religious submission but forensic vindication.</p>",
    "4": "<p><span class='term'>tōp̄ĕlê šāqer</span> — 'plasterers of falsehood' — <span class='term'>tāp̄al</span> is to plaster or coat over, used in Ezek 13:10-15 of prophets 'plastering' a flimsy wall with whitewash; the friends are applying a deceptive surface coating of doctrine to Job's situation without engaging its actual substance. <span class='term'>rōp̄ĕʾê ʾĕlîl</span> — 'physicians of worthlessness' — <span class='term'>ʾĕlîl</span> means 'nothingness/worthlessness' (the same word used for false gods in Lev 19:4; Isa 2:8); the friends' remedies are made of the same substance as idols — nothing.</p>",
    "5": "<p><span class='term'>mî-yittēn haḥărêš taḥărîšûn</span> — 'O that you would indeed keep completely silent' — the infinitive absolute haḥărêš intensifies the verb taḥărîšûn: 'truly keep silent.' <span class='term'>wĕtihî lāḵem lĕḥāḵmāh</span> — 'and it would be wisdom for you' — ironic wisdom-maxim: in your case, the wiser path is to stop speaking. Prov 17:28 makes the same point explicitly ('even a fool is counted wise when he holds his tongue'); Job anticipates and inverts the proverbial form by applying it to ostensible sages.</p>",
    "6": "<p><span class='term'>šimĕʿû-nāʾ tôḵaḥtî</span> — 'hear now my argument/reproof' — <span class='term'>tôḵaḥat</span> is the legal-wisdom term for rebuke, argument, or reproof (from yāḵaḥ, same root as v3); it appears in Prov 1:23; 29:15 for disciplinary correction. <span class='term'>wĕriḇôṯ śĕp̄āṯay haqšîḇû</span> — 'and give attention to the pleadings of my lips' — <span class='term'>rîḇ</span> is the formal legal dispute or lawsuit; Job is asking the friends to hear his actual legal argument rather than precluding it with theological frameworks.</p>",
    "7": "<p><span class='term'>hălĕʾêl tĕdabbĕrû ʿawlāh</span> — 'will you speak injustice on God's behalf?' — ʿawlāh is ethical injustice/wrong, not merely falsehood; Job is charging the friends with advocacy that is morally corrupt, not just factually mistaken. <span class='term'>ûlô tĕdabbĕrû rĕmiyyāh</span> — 'and for him speak deceit' — rĕmiyyāh is slackness/deception (cf. Ps 52:2 'tongue like a sharp razor, working deceit'). The accusation is that the friends are willing to lie for God — a form of false witness.</p>",
    "8": "<p><span class='term'>hăp̄ānāyw tiśśĕʾûn</span> — 'will you lift his face?' — nāśāʾ pānîm is the idiom for showing partiality/favoritism (lit. 'lifting the face' of the favored party); its prohibition runs through Lev 19:15; Deut 10:17; and the prophets. Job is accusing the friends of judicial bias — accepting God's side in the dispute without examining the evidence — which is precisely what law forbids. <span class='term'>lāʾĒl tĕrîḇûn</span> — 'will you contend for El?' — the same rîḇ vocabulary; they have appointed themselves God's lawyers in a case where God is a party.</p>",
    "9": "<p><span class='term'>hăṭôḇ kî-yĕḥqōr ʾetḵem</span> — 'is it good that he should search you out?' — if God examines the friends as he might examine any disputant, their advocacy will be exposed as partial and corrupt. <span class='term'>ʾim-kĕhāṯēl ʾĕnôš tĕhāṯĕlû-bô</span> — 'or will you deceive him as one deceives a mortal?' — hāṯal means to mock/deceive by playing tricks; the question exposes the absurdity of attempting to deceive God the way one might trick a credulous human adversary.</p>",
    "10": "<p><span class='term'>hôḵēaḥ yôḵîaḥ ʾetḵem</span> — 'he will certainly reprove you' — the doubled infinitive absolute (hôḵēaḥ yôḵîaḥ) emphasizes certainty of divine judgment against the friends; the same yāḵaḥ root that Job used in v3 (wanting to argue his own case before God) is now turned on the friends: the very divine court Job is invoking will find against them. <span class='term'>ʾim-bĕsēṯer pānîm tiśśĕʾûn</span> — 'if in secret you show favoritism' — the 'secret' aspect; what the friends do in their private reasoning, God exposes.</p>",
    "11": "<p><span class='term'>hălōʾ śĕʾēṯô tĕḇahēl ʾetḵem</span> — 'will not his majesty terrify you?' — śĕʾēṯô is 'his rising/elevation' (from nāśāʾ), used as a term for divine majesty or the awesome upwelling of divine presence. <span class='term'>wĕp̄aḥdô yippōl ʿălêḵem</span> — 'and his dread fall upon you' — paḥad (dread/terror) falling as a weight on a person is an OT theophanic language pattern; the same idea governs the theophanic visions of Isaiah (Isa 2:10,19; 6:5) and Job's own encounter (23:15-16).</p>",
    "12": "<p><span class='term'>zikrōnêḵem mišlê ʾēp̄er</span> — 'your wise maxims are proverbs of ash' — <span class='term'>mišlê ʾēp̄er</span> is a devastating compound: māšāl (proverb, wisdom saying) reduced to ʾēp̄er (ash/dust), the residue of burning. The friends' celebrated wisdom is literally the ash left after the fire of genuine insight has been extinguished. <span class='term'>ligbê-ḥōmer gabbêḵem</span> — 'your defenses/arguments are defenses of clay' — gaḇ (a raised defense or raised back?) modeled in clay (ḥōmer) — perishable, earthy, fragile.</p>",
    "13": "<p><span class='term'>haḥărîšû mimmennî wăʾăḏabbĕrāh ʾānî</span> — 'be silent, leave me alone, and let me speak' — Job asks for silence from the friends so he can present his case directly to God. <span class='term'>wĕyaʿăḇor ʿālay mah</span> — 'and let whatever comes, come upon me' — the fatalistic openness is deliberate; Job is willing to face whatever divine response his direct confrontation brings. The clause functions as an act of existential courage: consequences accepted in advance.</p>",
    "14": "<p><span class='term'>maddûaʿ ʾeśśāʾ bĕśārî bĕšinnay wĕnap̄šî ʾāśîm bĕkappî</span> — 'why do I take my flesh in my teeth and put my life in my hands?' — two idioms for extreme recklessness and mortal risk. Biting one's own flesh is a sign of desperation; 'putting one's life in one's hands' (nepeš + kap = palm) is a fixed idiom for risking death, used in Judg 12:3 and 1 Sam 19:5; 28:21. Job is asking rhetorically why he persists in a confrontation that could destroy him — yet proceeds anyway.</p>",
    "15": "<p><span class='term'>hēn yiqtĕlēnî lō ʾăyaḥēl</span> — the most disputed verse in the book. The Masoretic text has a qere/ketib variant: the written text (ketib) has <span class='term'>lō</span> (negative particle) = 'though he kills me, I have no hope'; the marginal reading (qere) has <span class='term'>lô</span> (to him) = 'though he kills me, yet I will hope in him.' The KJV ('yet will I trust in him') follows the qere. In context the latter reading coheres better: v16 ('this will be my salvation') and the whole trajectory of chs. 13–14 point toward a defiant hope rather than nihilism. The phrase <span class='term'>ʾaḵ-ḏĕrāḵay ʾel-pānāyw ʾôḵîaḥ</span> — 'but I will defend my ways before his face' — is unambiguous: Job intends to argue his case regardless of the outcome, which presupposes hope rather than its absence.</p>",
    "16": "<p><span class='term'>gam-hûʾ lî lîšûʿāh</span> — 'this itself will become my salvation' — gam-hûʾ ('even this' or 'he himself also') marks the paradox: the very confrontation with the God who might kill him (v15) will be the source of his vindication/salvation. <span class='term'>kî-lō-lĕp̄ānāyw ḥānēp̄ yāḇôʾ</span> — 'for the godless cannot come before his presence' — ḥānēp̄ is the impious/godless person (used 13x in Job); Job's argument is that his willingness to present himself before God is itself evidence he is not godless, since hypocrites cannot endure divine scrutiny.</p>",
    "17": "<p><span class='term'>šimĕʿû šāmôaʿ millātî</span> — 'hear carefully my declaration' — šāmôaʿ is the infinitive absolute intensifying šimĕʿû: truly/attentively hear. <span class='term'>ûʾaḥwāṯî bĕʾoznêḵem</span> — 'and my declaration into your ears' — ʾaḥwāh is to declare/show (from the root ḥwh, to show); Job is making a formal declaration that requires a formal hearing. The verse functions as a legal preamble to his ordered legal case in v18.</p>",
    "18": "<p><span class='term'>hinnēh-nāʾ ʿāraḵtî mišpāṭ</span> — 'look, I have ordered my case' — <span class='term'>ʿāraḵ mišpāṭ</span> is technical legal vocabulary: to marshal/arrange one's legal brief (ʿāraḵ = to set in order, as in battle array or the Tabernacle showbread; mišpāṭ = judgment/case). Job has prepared his legal case with the same deliberateness as setting up for a legal proceeding. <span class='term'>yāḏaʿtî kî-ʾāniʾ ʾeṣdāq</span> — 'I know that I will be justified/vindicated' — the verb ṣādaq in the nip'al means to be proved righteous or vindicated; Job's certainty of ultimate vindication is the basis of his courage.</p>",
    "19": "<p><span class='term'>mî-hûʾ yārîḇ ʿimmî</span> — 'who is there who will bring a charge against me?' — another legal formula; rîḇ + ʿim = to bring a dispute/charge against. The question is both a challenge (who can oppose me?) and an expression of Job's longing: he wants an adversary to appear so the case can be tried and won. <span class='term'>kî-ʿattāh ʾaḥărîš wĕʾegwaʿ</span> — 'for then I would be silent and die' — the conditional of despair: if no one can bring a charge and clear the air, Job would rather die in silence. The verse frames his speech as the only alternative to death by unresolved suffering.</p>",
    "20": "<p><span class='term'>ʾaḵ šĕtayim ʾal-taʿaś ʿimmî</span> — 'only do not do these two things to me' — Job makes a precise and limited request of God. <span class='term'>ʾāz mippāneyḵā lō ʾessātēr</span> — 'and then I will not hide myself from your presence' — the condition for Job's direct engagement with God is the removal of two impositions (named in v21): the divine hand and the divine dread. The hiddenness/presence language echoes 13:24 (why does God hide his face?) — Job's offer to stop hiding is contingent on God removing what makes his presence unbearable.</p>",
    "21": "<p><span class='term'>kappĕḵā mēʿālay harḥēq</span> — 'your hand — remove it far from me' — the divine hand (kap, palm/hand) as the instrument of affliction; removing it is the first condition. <span class='term'>wĕʾêmāṯĕḵā ʾal-tĕḇahălannî</span> — 'and do not let your terror overwhelm me' — ʾêmāh is numinous dread/terror (cf. 9:34; 33:7); bāhal in the piel means to terrify or throw into panic. Job cannot mount a rational legal case if God's terrifying presence overwrites his ability to think and speak coherently.</p>",
    "22": "<p><span class='term'>ûqrāʾ wĕʾānōḵî ʾeʿĕneh</span> — 'or let me speak first and you answer me' — the two alternatives for structuring the divine-human dialogue. Job is willing either to respond to God's call or to initiate and let God respond. The symmetry is striking: Job as respondent OR Job as initiator, both equally acceptable — the crucial thing is that the encounter happens. This is the most direct assertion of dialogic reciprocity between Job and God in the entire book.</p>",
    "23": "<p><span class='term'>kammāh lî ʿăwōnôṯ waḥaṭṭāʾôṯ</span> — 'how many are my iniquities and sins?' — ʿāwōn (moral iniquity, guilt) and ḥaṭṭāʾt (missing the mark, sin) are the two most common OT sin vocabulary words; Job's question is not rhetorical denial but a genuine desire to know the specific charges against him. <span class='term'>pišʿî wĕḥaṭṭāʾṯî hôḏîʿēnî</span> — 'make my transgression and my sin known to me' — pešaʿ is rebellion/willful transgression (the most morally serious of the three terms); Job uses all three sin-words together, covering the full spectrum, as if to say: whatever I have done, just show me what it is.</p>",
    "24": "<p><span class='term'>lāmmāh-p̄āneyḵā tastîr</span> — 'why do you hide your face?' — the divine face-hiding (hester pānîm) is a major OT theological motif (Ps 13:1; 27:9; Isa 8:17; 45:15); it denotes divine withdrawal that leaves the sufferer in darkness and abandonment. Job is calling God to account for a hidden-face experience that he has done nothing to merit. <span class='term'>wĕtiḥšĕḇēnî lĕʾôyēḇ lāḵ</span> — 'and regard me as your enemy?' — ʾôyēḇ (enemy); Job protests that God's behavior toward him is indistinguishable from how one treats a hostile enemy.</p>",
    "25": "<p><span class='term'>hăʿaleh nidāp̄ tĕʿārôṣ</span> — 'will you pursue a wind-driven leaf?' — nādap̄ means blown/driven (as in Isa 19:7 of reeds by a river); the image is of a completely powerless, insubstantial object that poses no threat. <span class='term'>wĕʾet-qǎš yābēš tirḏōp̄</span> — 'and chase after dry stubble?' — qāš is the chaff/stubble; rādap̄ is to pursue with hostile intent (the verb for persecution). The incongruity of the Almighty chasing a dried leaf and stubble makes Job's suffering appear cosmically disproportionate to any supposed offense.</p>",
    "26": "<p><span class='term'>kî-ṯiḵtōḇ ʿālay merōrôṯ</span> — 'for you write bitter things against me' — the image of written charges is a legal motif; God is cast as a plaintiff filing a formal written indictment (mĕrōrôṯ = bitter things/bitter charges). <span class='term'>wĕṯôrîšēnî ʿăwōnôṯ nĕʿûrāy</span> — 'and saddle me with the sins of my youth' — the imputed sins of youth (nōʿar = youth) are the charge-content; Job protests that God is charging him with offenses from an earlier life, a form of injustice since the normal moral logic assumes such debts have been settled or left behind.</p>",
    "27": "<p><span class='term'>wĕtāśem bassad raglāy</span> — 'you put my feet in stocks' — sāḏ is the stock or wooden restraint for prisoners; applied to a righteous man it is a judicial travesty. <span class='term'>ûtiśmōr kol-ʾorḥōṯāy</span> — 'and keep watch over all my paths' — šāmar in the sense of surveillance rather than protection (the same verb used for guarding/keeping in Gen 3:24); God as warden rather than shepherd. <span class='term'>ʿal-šorĕšê raglay tĕṯḥaqqeh</span> — 'you mark the prints of my feet' — ḥāqaq means to inscribe/engrave; God etching the footprint-marks as permanent evidence, as one documents the movements of a prisoner.</p>",
    "28": "<p><span class='term'>wĕhûʾ kĕrāqāḇ yibleh</span> — 'and he wastes away like a rotten thing' — rāqāḇ is decay/rottenness (wood-rot or general decomposition); the shift to third-person 'he' from the preceding 'I' signals that v28 either summarizes Job's condition from outside or is a scribal connection. <span class='term'>kĕbegeḏ ʾăḵālô ʿāš</span> — 'like a garment eaten by moths' — the moth-eating-garment metaphor for gradual, invisible deterioration; the same image appears in Job 4:19; Isa 50:9; 51:8; and Matt 6:19. The chapter closes on an image of quiet dissolution rather than dramatic collapse.</p>"
  },
  "14": {
    "1": "<p><span class='term'>ʾāḏām yĕlûḏ-ʾiššāh</span> — 'man born of woman' — the phrase is a formal identification of human creatureliness: to be born is to be limited, mortal, and embedded in the generational chain of finitude. This exact phrase recurs in Job 15:14 and 25:4 (where Bildad uses it to deny human purity before God) and enters the NT in Gal 4:4 ('born of woman, born under the law'). <span class='term'>qĕṣar-yāmîm ûśĕḇaʿ-rōgez</span> — 'short of days and full of agitation' — rōgez is turmoil, agitation, trembling (cf. Isa 14:3 where rest from rōgez is promised to the oppressed); the two phrases together give the double diagnosis of human existence: brief and troubled.</p>",
    "2": "<p><span class='term'>kĕṣîṣ yāṣāʾ wayyimmāl</span> — 'like a flower he comes up and is cut off' — <span class='term'>nāmal</span> (to be cut off/wither) is used here as in Ps 90:6 for the brief flourishing of human life; the flower metaphor for human transience appears also in Isa 40:6-8 ('all flesh is like grass... the flower of the field') and 1 Pet 1:24. <span class='term'>wĕlō yāʿăḇōr</span> — 'and he does not endure/pass over' — ʿāḇar normally means to cross/pass over; here the sense is 'he does not persist' or 'he does not abide,' reinforcing the shadow-image of v2b.</p>",
    "3": "<p><span class='term'>ʾap̄-ʿal-zeh p̄āqaḥtā ʿêneyḵā</span> — 'yet on such a one do you open your eyes?' — p̄āqaḥ ʿênayim is to open the eyes with scrutinizing attention; the question is almost incredulous: this frail, ephemeral creature is the object of divine forensic attention? <span class='term'>wĕʾōṯî ṯāḇîʾ bĕmišpāṭ ʿimmāḵ</span> — 'and bring me into court with you?' — mišpāṭ + bôʾ ʿim = judicial proceeding; the disproportion between the creature's fragility (v1-2) and the solemnity of the divine court is Job's complaint.</p>",
    "4": "<p><span class='term'>mî-yittēn ṭāhôr miṭṭāmēʾ lō ʾeḥāḏ</span> — 'who can bring something pure from something impure? Not one' — this is one of the most theologically dense one-line statements in Job. ṭāhôr/ṭāmēʾ (pure/impure) are the cultic purity categories; the rhetorical question with the answer 'not one' (lō ʾeḥāḏ) asserts the universal impossibility of purity arising from impurity. Paul in Rom 3:10-12 strings together similar ʾeḥāḏ / 'not one' statements from the Psalms; the logic of universal human uncleanness that undergirds the need for an external righteousness begins to take shape here.</p>",
    "5": "<p><span class='term'>ʾim ḥărûṣîm yāmāyw</span> — 'since his days are determined/decided' — ḥāraṣ means to cut/decide; the passive participle ḥărûṣîm = 'decreed/fixed' (cf. Dan 9:24-26 where the same root governs divinely determined periods of history). <span class='term'>mispār ḥŏḏāšāyw ʾittĕḵā</span> — 'the number of his months is with you' — the months of human life are God's to count, not the human's to determine. <span class='term'>ḥuqqāyw ʿāśîṯā wĕlō yaʿăḇōr</span> — 'you have set his limit that he cannot cross' — ḥōq (a fixed statutory limit) functions here as Job's argument for why God should ease up: if the limits are already fixed, there is no point maintaining adversarial pressure.</p>",
    "6": "<p><span class='term'>šĕʿēh mēʿālāyw wĕyiḥdāl</span> — 'look away from him so he can rest' — šāʿāh (to look away, avert gaze) used with mēʿālāyw (from upon him) — the request is simply for divine inattention, the relief of not being watched. <span class='term'>ʿaḏ-yirṣeh kĕśākîr yômô</span> — 'until he completes, like a hired worker, his day' — the hired worker (śākîr) simile: a day-laborer's term of service is finite and acknowledged; at its end he has rest and his wages. Job is asking for a similar finitude of divine attention.</p>",
    "7": "<p><span class='term'>yēš tiqwāh lāʿēṣ</span> — 'there is hope for a tree' — the word <span class='term'>tiqwāh</span> (hope, from qāwāh = to wait/hope) is used here for the first time in the chapter in a positive sense, though its application is to a tree rather than a human. The tree-hope becomes a foil for human hopelessness in vv10-12. <span class='term'>wĕḥôṭer miggizʿô lō yĕḥdāl</span> — 'and its new shoot will not stop' — ḥōṭer is a young shoot or sucker growing from a cut stump; gizʿāh is the stump; the tree regenerates from below ground even after being severed. The image of hope-through-remnant anticipates the messianic stump imagery of Isa 11:1 ('a shoot will come up from the stump of Jesse').</p>",
    "8": "<p><span class='term'>ʾim-yazzîn bāʾāreṣ šorĕšô</span> — 'though its root grows old in the earth' — zāqan (to be old, to age) applied to a root hidden in soil; even if the visible part of the tree is gone, the aging root persists underground. <span class='term'>wĕbĕʿāpār yāmûṯ gizʿô</span> — 'and its stump dies in the dust' — gizʿāh (stump); māwet (death); ʿāpār (dust/earth). The imagery of death-in-dust will be reversed in v9 by the water-scent miracle, setting up the contrast with humanity in v10.</p>",
    "9": "<p><span class='term'>mērêaḥ mayim yapprîaḥ</span> — 'at the scent of water it blossoms' — the tree's response to water is spontaneous and irrepressible: pāraḥ (to blossom/sprout) triggered by mere rêaḥ (smell/scent) of water. The sensory detail (smell, not taste or touch) emphasizes the tree's deep responsiveness to life-conditions. <span class='term'>wĕʿāśāh qaṣîr kĕnāṭaʿ</span> — 'and makes branches like a new plant' — the dead stump recovering to produce fresh growth ('like a new plant') is the image of resurrection without using the word; the trajectory from vv7-9 models renewal-from-death precisely to set up the contrast with human mortality in vv10-12.</p>",
    "10": "<p><span class='term'>wĕgāḇer yāmûṯ wayyeḥĕlaš</span> — 'but man dies and falls helpless' — wayyeḥĕlaš from ḥālaš = to be weak/prostrate; the contrast with the tree's vigorous resprouting is stark. <span class='term'>wĕgāwaʿ ʾāḏām wĕʾayyô</span> — 'and man breathes his last — and where is he?' — gāwaʿ is the verb of expiration (breathing out the last breath); ʾayyô is the haunting interrogative 'where is he?', which carries the same existential weight as Cain's 'am I my brother's keeper?' (Gen 4:9) and the angels' 'man, where are you?' (Gen 3:9). The 'where?' question will echo in the Resurrection proclamation.</p>",
    "11": "<p><span class='term'>ʾāzĕlû mayim miyyām</span> — 'as waters vanish from the sea' — āzal (to go away, to be gone; used very rarely, possibly related to a root meaning 'to exhaust'). The simile of water draining from a lake (yām can be any body of water) introduces the first of three water-failure images (v11: lake; v12a: river) that parallel human death. <span class='term'>wĕnāhār yeḥĕraḇ wĕyāḇēš</span> — 'and a river wastes and dries up' — ḥāraḇ (to be dry/desolate, the root of ḥōreḇ = desert) and yāḇēš (to dry up) together describe total desiccation with no prospect of return.</p>",
    "12": "<p><span class='term'>wĕʾîš šāḵaḇ wĕlō-yāqûm</span> — 'man lies down and does not rise' — the water-failure simile completed: as water drains irreversibly, so man lies down irreversibly. The key phrase is the temporal clause: <span class='term'>ʿaḏ-biltî šāmayim lō yêqîṣû</span> — 'until the heavens are no more, they will not wake.' <span class='term'>biltî</span> is a negative particle (without/unless); the clause literally 'until the failure/absence of heavens, they will not awake.' This does not close the door on resurrection — it opens it: when the heavens finally end (as Isa 34:4; 51:6; Rev 21:1 affirm they will), the sleepers will wake. The clause is eschatologically charged.</p>",
    "13": "<p><span class='term'>mî-yittēn bišʾôl taps̈pĕnēnî</span> — 'O that you would hide me in Sheol!' — the optative mî-yittēn ('who will give?' = O that!) expressing a wish; Job's longing is for Sheol not as final destination but as temporary shelter from divine wrath. The phrase <span class='term'>taps̈pĕnēnî</span> (from ṣāp̄an = to hide/store) uses the same verb as Ps 31:19 ('how great is your goodness which you have stored up [ṣāp̄antā] for those who fear you') — hiding in Sheol paradoxically connects to the divine storage of the righteous. <span class='term'>ṯāšît lî ḥōq wĕtizkĕrēnî</span> — 'set a fixed time for me and remember me!' — ḥōq (appointed/fixed limit) and zāḵar (remember); Job asks for a divine appointment in Sheol from which God will eventually summon him back, using the covenant-recall language of divine remembrance (cf. Gen 8:1, 'God remembered Noah').</p>",
    "14": "<p><span class='term'>ʾim-yāmûṯ gāḇer hăyiḥyeh</span> — 'if a man dies, will he live again?' — the resurrection question, the hinge of the chapter and one of the most theologically significant single-verse questions in the OT. <span class='term'>ḥāyāh</span> (to live) after māwet is either the question of resuscitation (will he simply revive?) or resurrection (will he be raised to new life?). The NT uses this exact logic-of-impossibility-now-made-possible structure in John 11:25 ('I am the resurrection and the life'). <span class='term'>kol-yĕmê ṣĕḇāʾî ʾăyaḥēl ʿaḏ-bôʾ ḥălîp̄āṯî</span> — 'all the days of my hard service I will wait until my release comes' — ṣāḇāʾ is military service/hard labor (used also in Isa 40:2 for Jerusalem's completed 'hard service'); ḥălîp̄āh is exchange/relief (from ḥālap̄ = to pass through, to change; used of a military rotation). Job envisions waiting in a post-mortem state of service until a divinely decreed moment of exchange/relief arrives — the closest OT parallel to a resurrection hope.</p>",
    "15": "<p><span class='term'>tiqrāʾ wĕʾānōḵî ʾeʿĕneh</span> — 'you will call and I will answer' — the restoration of the divine-human dialogue broken by death; in Job's vision of the post-mortem state, God calls and Job responds. This is the inverse of the divine silence Job experiences in the present. <span class='term'>tiḵsōp̄ lĕmaʿăśēh yāḏeyḵā</span> — 'you will long for the work of your hands' — <span class='term'>kāsap̄</span> means to long for/desire with yearning (used in Gen 31:30 of Laban longing for his household gods; Ps 84:2 of the soul longing for God's courts). God longing for his own handiwork (Job) is a remarkable attribution: the Creator is portrayed as yearning for the creature he made. This verse is the theological counterweight to all of Job's complaint — the ultimate frame is divine yearning, not divine indifference.</p>",
    "16": "<p><span class='term'>kî-ʿattāh ṣĕʿādî tispôr</span> — 'for now you count my every step' — sāpar (to count/number) applied to steps; the divine surveillance experienced not as care but as obsessive prosecution. The contrast with v15 is sharp: there, God yearns; here (in present reality), God prosecutes. <span class='term'>lō-ṯišmôr ʿal-ḥaṭṭāʾṯî</span> — 'you do not overlook my sin' — in the hoped-for future relationship (v15), the implication is that God will choose not to prosecute every infraction; in the present, none escapes. The verse captures the present experience of grace-less divine scrutiny that makes existence unbearable.</p>",
    "17": "<p><span class='term'>ḥātûm bĕṣerôr pišʿî</span> — 'my transgression sealed in a bag' — ṣārôr is a knotted pouch or bundle; pešaʿ (willful transgression) sealed inside it as if God is storing the evidence. <span class='term'>wattipĕl ʿal-ʿăwōnî</span> — 'and you stitch up my iniquity' — ṭāpal (to plaster/fasten over); the image is of God sealing and stitching shut the bag of Job's sins so nothing escapes the eventual reckoning. The forensic archive metaphor: God as keeper of perfectly preserved prosecutorial records.</p>",
    "18": "<p><span class='term'>wĕʾûlām hār-nôp̄ēl yibbôl</span> — 'and surely a falling mountain crumbles' — the erosion section (vv18-19) uses geological imagery for the human condition under divine attrition. nāpal (to fall) + nāḇal (to decay/crumble); a collapsing mountain erodes over time rather than in a single dramatic event, mirroring the slow dissolution of Job's hope. <span class='term'>wĕṣûr yeʿĕtaq mimmĕqōmô</span> — 'and the rock is displaced from its place' — ʿātaq (to move on/pass over, used in Gen 12:8 of Abram moving on); rocks considered immovable are yet dislodged by geological processes — another impossibility-become-possible that grounds Job's eschatological hope.</p>",
    "19": "<p><span class='term'>ʾăḇānîm šāḥăqû mayim</span> — 'waters wear away stones' — šāḥaq (to wear down/pulverize, from which šāḥaq = fine dust/sky) used of water's slow grinding effect on rock; the same inexorable attrition applies to human hope. <span class='term'>tišṭōp̄ sĕpîḥeyāh ʿăp̄ar-ʾāreṣ</span> — 'its floods wash away the dust of the earth' — šāṭap̄ (to overflow/wash away) of floodwaters sweeping the topsoil away. <span class='term'>wĕtiqwaṯ ʾĕnôš ʾibbadtāh</span> — 'and the hope of man you destroy' — tiqwāh (hope, the same root used for the tree's hope in v7) now applied to man and declared destroyed; the geological erosion is the metaphor for the erosion of hope. Job returns to tiqwāh to close the circle from v7.</p>",
    "20": "<p><span class='term'>tĕqāp̄ēhû lāneṣaḥ wayyēlek</span> — 'you overpower him once and he is gone forever' — lāneṣaḥ (forever, perpetually); the divine coup de grâce is delivered once (not repeatedly) but is permanent. <span class='term'>mĕšanneh p̄ānāyw waṯĕšallĕḥēhû</span> — 'you alter his face and send him away' — šānāh (to change); the alteration of the face at death — the features becoming unrecognizable, strange. The sending-away (šālaḥ) is a dismissal; life is a temporary summons and death is the dismissal after the audience.</p>",
    "21": "<p><span class='term'>yikbĕḏû bānāyw wĕlō-yēḏāʿ</span> — 'his sons rise to honor and he does not know it' — yāḏaʿ (to know) is the verb of epistemological isolation; the father in Sheol cannot perceive the progress or regress of his children. <span class='term'>wĕyiṣʿărû wĕlō-yāḇîn lāmô</span> — 'they are brought low and he does not understand' — the double ignorance (honor and dishonor) is equally unknown; post-mortem existence as total epistemic isolation from earthly life. The verse is one of the OT's clearest statements of the disembodied state's disconnection from history.</p>",
    "22": "<p><span class='term'>ʾaḵ-bĕśārô ʿālāyw yikʾāḇ</span> — 'but his flesh feels pain within him' — kāʾab (to feel pain/be grieved); the final verse describes the dying/dead man's last experience: exclusively inward, bodily pain. <span class='term'>wĕnap̄šô ʿālāyw tiʾēḇāl</span> — 'and his soul mourns over himself' — ʾāḇal (to mourn, used for mourning the dead); the soul's grief is reflexive — mourning itself rather than others. The chapter that began with man's brief, troubled existence (v1) ends with pain and self-mourning: the most existentially isolated possible image of death, which makes Job's expressed hope in vv13-15 all the more remarkable.</p>"
  }
}

def main():
    c = load_comm('mkt-original', 'job')
    merge_comm(c, JOB1214)
    save_comm('mkt-original', 'job', c)
    count = sum(len(v) for v in JOB1214.values())
    print(f'job mkt-original: wrote {count} verses for ch 12–14')

if __name__ == '__main__':
    main()
